import{_ as e,o as a,c as o,a2 as r}from"./chunks/framework.Crpw6aS5.js";const u=JSON.parse('{"title":"董事会与公司治理 Corporate Governance","description":"一个被严重低估的核心主题","frontmatter":{"title":"董事会与公司治理 Corporate Governance","description":"一个被严重低估的核心主题"},"headers":[],"relativePath":"02_concepts/corporate-governance.md","filePath":"02_concepts/corporate-governance.md"}'),l={name:"02_concepts/corporate-governance.md"};function n(p,t,h,s,i,c){return a(),o("div",null,[...t[0]||(t[0]=[r('<h1 id="董事会与公司治理-corporate-governance" tabindex="-1">董事会与公司治理 Corporate Governance <a class="header-anchor" href="#董事会与公司治理-corporate-governance" aria-label="Permalink to &quot;董事会与公司治理 Corporate Governance&quot;">​</a></h1><blockquote><p>&quot;董事会存在的意义，是确保公司为股东服务，而不是管理层为自己服务。如果董事会做不到这一点，股东就是砧板上的鱼肉。&quot; ——<a href="/04_people/沃伦·巴菲特.html">沃伦·巴菲特</a></p></blockquote><hr><h2 id="核心出处" tabindex="-1">核心出处 <a class="header-anchor" href="#核心出处" aria-label="Permalink to &quot;核心出处&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">年份</th><th style="text-align:left;">重点内容</th></tr></thead><tbody><tr><td style="text-align:left;">**[[/01_letters/1992年/核心总结</td><td style="text-align:left;">1992年]]**</td></tr><tr><td style="text-align:left;">**[[/01_letters/1993年/核心总结</td><td style="text-align:left;">1993年]]**</td></tr><tr><td style="text-align:left;">**[[/01_letters/2002年/核心总结</td><td style="text-align:left;">2002年]]**</td></tr><tr><td style="text-align:left;">**[[/01_letters/2003年/核心总结</td><td style="text-align:left;">2003年]]**</td></tr><tr><td style="text-align:left;">**[[/01_letters/2008年/核心总结</td><td style="text-align:left;">2008年]]**</td></tr><tr><td style="text-align:left;">**[[/01_letters/2014年/核心总结</td><td style="text-align:left;">2014年]]**</td></tr><tr><td style="text-align:left;">**[[/01_letters/2018年/核心总结</td><td style="text-align:left;">2018年]]**</td></tr></tbody></table><p>:::{.callout .note} <strong>数据注脚</strong>：在整个巴菲特股东信语料库中，&quot;董事会&quot;一词出现<strong>863次</strong>，2014年单年达到<strong>101次</strong>峰值——这一主题被市场严重低估，却是理解现代公司治理痼疾的关键切口。 :::</p><hr><h2 id="为什么董事会问题长期被忽视" tabindex="-1">为什么董事会问题长期被忽视？ <a class="header-anchor" href="#为什么董事会问题长期被忽视" aria-label="Permalink to &quot;为什么董事会问题长期被忽视？&quot;">​</a></h2><p>大多数投资者在分析一家公司时，首先看财务数据、行业地位、管理团队——却很少有人真正审视那家公司的<strong>董事会结构</strong>。</p><p>这是一个危险的盲区。</p><p><a href="/04_people/沃伦·巴菲特.html">巴菲特</a>在1992年首次系统性地将矛头指向董事会问题。他指出：公司治理失败的根源，往往不是管理层&quot;变坏&quot;了，而是<strong>监督机制从一开始就是缺失的</strong>——而这个监督机制，正是董事会。</p><blockquote><p>&quot;我们经常听到投资者抱怨管理层的薪酬过高、并购决策愚蠢、信息披露不透明。但很少有人追问：是谁批准了这一切？是谁在监督管理层？答案是：董事会——一个在大多数公司里，几乎不发挥作用的机构。&quot; ——<a href="/04_people/沃伦·巴菲特.html">沃伦·巴菲特</a>，《<a href="/03_companies/伯克希尔哈撒韦.html">伯克希尔</a>·哈撒韦致股东信》，1992年</p></blockquote><p>他用一个辛辣的比喻形容大多数美国公司董事会：<strong>&quot;看门狗&quot;被养在主人家里，却对主人摇尾巴。</strong></p><hr><h2 id="问题的根源-董事遴选机制的内在缺陷" tabindex="-1">问题的根源：董事遴选机制的内在缺陷 <a class="header-anchor" href="#问题的根源-董事遴选机制的内在缺陷" aria-label="Permalink to &quot;问题的根源：董事遴选机制的内在缺陷&quot;">​</a></h2><h3 id="你选我当董事-我选你当董事" tabindex="-1">&quot;你选我当董事，我选你当董事&quot; <a class="header-anchor" href="#你选我当董事-我选你当董事" aria-label="Permalink to &quot;&quot;你选我当董事，我选你当董事&quot;&quot;">​</a></h3><p><a href="/04_people/沃伦·巴菲特.html">巴菲特</a>在1993年的信中，一针见血地指出了董事遴选机制的根本性问题：</p><blockquote><p>&quot;美国公司董事的提名，本质上是一种&#39;内部交易&#39;。现任 CEO 推荐下届董事候选人，下届董事在当选后投票支持现任 CEO——这是一套精心设计的互利机制，而不是为股东服务的机制。&quot; ——<a href="/04_people/沃伦·巴菲特.html">沃伦·巴菲特</a>，《<a href="/03_companies/伯克希尔哈撒韦.html">伯克希尔</a>·哈撒韦致股东信》，1993年</p></blockquote><p>在这样的机制下，董事候选人最重要的&quot;资质&quot;，往往不是商业判断力、财务专业知识或独立性，而是<strong>与管理层的友好关系</strong>。</p><blockquote><p>&quot;我见过一些公司的董事会，里面坐满了退休的高管、学者的配偶、CEO 的大学同学——这些人有一个共同点：对管理层永远说&#39;是&#39;。他们不是坏蛋，他们只是没有资格扮演监督者的角色。&quot; ——<a href="/04_people/沃伦·巴菲特.html">沃伦·巴菲特</a>，《<a href="/03_companies/伯克希尔哈撒韦.html">伯克希尔</a>·哈撒韦致股东信》，1993年</p></blockquote><h3 id="利益冲突-独立董事不独立" tabindex="-1">利益冲突：独立董事不独立 <a class="header-anchor" href="#利益冲突-独立董事不独立" aria-label="Permalink to &quot;利益冲突：独立董事不独立&quot;">​</a></h3><p><a href="/04_people/沃伦·巴菲特.html">巴菲特</a>对&quot;独立董事&quot;（Independent Director）这一概念持深度怀疑态度——不是因为独立董事本身不好，而是因为<strong>现实中的&quot;独立&quot;往往是虚假的</strong>。</p><blockquote><p>&quot;公司董事会中，大多数董事在法律上被称为&#39;独立董事&#39;，但实际上，他们从公司获得的咨询费、演讲费、股票期权或慈善捐赠，远超他们的董事薪酬。在这种情况下，你怎么能期待他们真正&#39;独立&#39;？&quot; ——<a href="/04_people/沃伦·巴菲特.html">沃伦·巴菲特</a>，《<a href="/03_companies/伯克希尔哈撒韦.html">伯克希尔</a>·哈撒韦致股东信》，2003年</p></blockquote><p>他进一步解释：真正的独立，需要同时满足两个条件——<strong>既没有经济利益，也没有社会关系</strong>。而大多数公司董事会，这两个条件都难以满足。</p><blockquote><p>&quot;如果一个董事的儿子在为公司的投资银行工作，如果一个董事在公司的慈善基金会担任顾问，如果一个董事与管理层的核心成员是高尔夫球友——他们就不是独立的，无论他们的简历上怎么写。&quot; ——<a href="/04_people/沃伦·巴菲特.html">沃伦·巴菲特</a>，《<a href="/03_companies/伯克希尔哈撒韦.html">伯克希尔</a>·哈撒韦致股东信》，2003年</p></blockquote><hr><h2 id="董事会的真正职责" tabindex="-1">董事会的真正职责 <a class="header-anchor" href="#董事会的真正职责" aria-label="Permalink to &quot;董事会的真正职责&quot;">​</a></h2><p><a href="/04_people/沃伦·巴菲特.html">巴菲特</a>并不认为董事会应该被废除——相反，他始终认为一个<strong>有效的</strong>董事会，是公司治理不可或缺的组成部分。关键在于，什么才是&quot;有效的董事会&quot;。</p><h3 id="职责一-选拔和监督ceo" tabindex="-1">职责一：选拔和监督CEO <a class="header-anchor" href="#职责一-选拔和监督ceo" aria-label="Permalink to &quot;职责一：选拔和监督CEO&quot;">​</a></h3><p>董事会的第一职责，是为股东挑选一位合格的 CEO，并在其任期内持续评估其表现。这包括：</p><ul><li>在 CEO 表现不佳时及时干预</li><li>在必要时果断更换 CEO</li><li>评估 CEO 的继任人选</li></ul><blockquote><p>&quot;董事会最重要的决定，是选择 CEO 这个决定。这个决定做对了，其他大多数决定都可以弥补；这个决定做错了，其他所有决定都无济于事。&quot; ——<a href="/04_people/沃伦·巴菲特.html">沃伦·巴菲特</a>，《<a href="/03_companies/伯克希尔哈撒韦.html">伯克希尔</a>·哈撒韦致股东信》，1992年</p></blockquote><h3 id="职责二-资本配置监督" tabindex="-1">职责二：资本配置监督 <a class="header-anchor" href="#职责二-资本配置监督" aria-label="Permalink to &quot;职责二：资本配置监督&quot;">​</a></h3><p>董事会还应承担资本配置的监督责任——包括审批重大投资、收购、剥离和分红决策。</p><p><a href="/04_people/沃伦·巴菲特.html">巴菲特</a>批评了许多公司董事会在重大并购案中的失职：董事们往往只是在管理层呈上的华丽PPT前点头通过，而没有进行</p>',35)])])}const q=e(l,[["render",n]]);export{u as __pageData,q as default};
